sql:
SELECT COUNT(character_id) AS completed_count
FROM quests_characters
WHERE quest_id = 1;

SELECT COUNT(character_id) AS total_members
FROM character_guilds
WHERE guild_id = 1;

external_knowledge:
- "battle achievements" refers to the calculation of combat score based on wins, losses, and draws;
- "quest accomplishments" refers to the number of completed quests multiplied by 5;
- "leadership roles" refers to the bonus points assigned to characters who are leaders of a guild.

sql:
SELECT quest_name, difficulty_level
FROM quests
ORDER BY difficulty_level DESC;
